const parseJson = (value, fallback) => {
  try {
    const parsed = JSON.parse(String(value || '').trim());
    return parsed ?? fallback;
  } catch {
    return fallback;
  }
};

const item = $input.first().json;
const sources = parseJson(item.sourcesJson, []);
const config = {
  publicBaseUrl: String(item.publicBaseUrl || '').replace(/\/+$/, ''),
  websitePath: String(item.websitePath || 'daily-news-show').replace(/^\/+/, ''),
  ttlHours: Number(item.ttlHours || 48),
  lookbackHours: Number(item.lookbackHours || 36),
  summaryMaxChars: Number(item.summaryMaxChars || 380),
  maxByTopic: {
    regional: Number(item.maxRegional || 4),
    politics: Number(item.maxPolitics || 4),
    tech: Number(item.maxTech || 3),
    economy: Number(item.maxEconomy || 3),
    traffic: Number(item.maxTraffic || 2),
    warnings: Number(item.maxWarnings || 2),
    energy: Number(item.maxEnergy || 2),
    ai: Number(item.maxAi || 2)
  },
  topicOrder: parseJson(item.topicOrderJson, ['regional', 'politics', 'tech', 'economy', 'traffic', 'warnings', 'energy', 'ai']),
  sectionConfig: parseJson(item.sectionConfigJson, []),
  germanFocusRegex: String(item.germanFocusRegex || '(deutschland|europa|ulm|dornstadt)')
};

return (Array.isArray(sources) ? sources : [])
  .filter((s) => s && typeof s === 'object')
  .filter((s) => String(s.type || '').toLowerCase() === 'rss')
  .filter((s) => typeof s.url === 'string' && s.url.trim())
  .map((source) => ({
    json: {
      source: {
        sourceId: String(source.sourceId || 'unknown'),
        label: String(source.label || 'Quelle'),
        topic: String(source.topic || 'general'),
        type: 'rss',
        url: String(source.url).trim()
      },
      config
    }
  }));

const src = $('Split Sources').item.json.source || {};
const config = $('Split Sources').item.json.config || {};

if ($json.error || $json.message) {
  return {
    json: {
      config,
      sourceResult: {
        sourceId: src.sourceId || 'unknown',
        label: src.label || 'Unknown source',
        topic: src.topic || 'general',
        status: 'error',
        error: String($json.message || $json.error || 'HTTP error'),
        items: []
      }
    }
  };
}

const raw = typeof $json === 'string' ? $json : String($json.data || $json.body || $json.response || '');

const decode = (text) => String(text || '')
  .replace(/<!\[CDATA\[(.*?)\]\]>/gs, '$1')
  .replace(/<[^>]*>/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&quot;/g, '"')
  .replace(/&#39;/g, String.fromCharCode(39))
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/\s+/g, ' ')
  .trim();

const getTag = (block, tag) => {
  const escaped = tag.replace(':', '\\:');
  const match = block.match(new RegExp(`<${escaped}[^>]*>([\\s\\S]*?)<\/${escaped}>`, 'i'));
  return decode((match || [])[1] || '');
};

const items = [];

const rssRegex = /<item>([\s\S]*?)<\/item>/gi;
let m;
while ((m = rssRegex.exec(raw)) !== null) {
  const block = m[1];
  const title = getTag(block, 'title');
  const url = getTag(block, 'link');
  const publishedRaw = getTag(block, 'pubDate') || getTag(block, 'dc:date');
  const summary = getTag(block, 'description') || getTag(block, 'content:encoded');
  if (!title || !url) continue;
  const ts = publishedRaw ? Date.parse(publishedRaw) : NaN;
  items.push({
    title,
    url,
    summary,
    sourceId: src.sourceId || 'unknown',
    source: src.label || 'Quelle',
    topic: src.topic || 'general',
    publishedAt: Number.isFinite(ts) ? new Date(ts).toISOString() : null
  });
}

const atomRegex = /<entry[\s\S]*?>([\s\S]*?)<\/entry>/gi;
while ((m = atomRegex.exec(raw)) !== null) {
  const block = m[1];
  const title = getTag(block, 'title');
  const linkMatch = block.match(/<link[^>]*href="([^"]+)"[^>]*>/i) || block.match(/<link[^>]*href='([^']+)'[^>]*>/i);
  const url = decode((linkMatch || [])[1] || getTag(block, 'link'));
  const publishedRaw = getTag(block, 'updated') || getTag(block, 'published');
  const summary = getTag(block, 'summary') || getTag(block, 'content');
  if (!title || !url) continue;
  const ts = publishedRaw ? Date.parse(publishedRaw) : NaN;
  items.push({
    title,
    url,
    summary,
    sourceId: src.sourceId || 'unknown',
    source: src.label || 'Quelle',
    topic: src.topic || 'general',
    publishedAt: Number.isFinite(ts) ? new Date(ts).toISOString() : null
  });
}

return {
  json: {
    config,
    sourceResult: {
      sourceId: src.sourceId || 'unknown',
      label: src.label || 'Unknown source',
      topic: src.topic || 'general',
      status: 'ok',
      error: null,
      items
    }
  }
};

const rows = $input.all().map((i) => i.json || {});
const cfg = rows[0]?.config || {};
const sourceResults = rows.map((r) => r.sourceResult).filter(Boolean);

const now = Date.now();
const lookbackHours = Math.max(1, Number(cfg.lookbackHours || 36));
const minTs = now - lookbackHours * 3600 * 1000;
const maxByTopic = cfg.maxByTopic || {};

const toPlain = (s) => String(s || '').replace(/\s+/g, ' ').trim();
const normalize = (s) => toPlain(s).toLowerCase().replace(/https?:\/\/[^\s]+/g, '').replace(/[^a-z0-9\u00e4\u00f6\u00fc\u00df\s]/g, ' ').replace(/\s+/g, ' ').trim();
const germanRegex = new RegExp(String(cfg.germanFocusRegex || '(deutschland|europa|ulm|dornstadt)'), 'i');
const badTitle = /(dpa-meldungen|ad hoc|börse express|boerse express|\+\+\+|ticker|liveblog)/i;

const all = [];
for (const sr of sourceResults) {
  const items = Array.isArray(sr.items) ? sr.items : [];
  for (const it of items) {
    const title = toPlain(it.title);
    const url = toPlain(it.url);
    if (!title || !url) continue;
    const summary = toPlain(it.summary);
    const publishedTs = it.publishedAt ? Date.parse(it.publishedAt) : NaN;
    if (Number.isFinite(publishedTs) && publishedTs < minTs) continue;
    if (badTitle.test(title)) continue;
    all.push({
      title,
      url,
      summary,
      source: toPlain(it.source),
      topic: toPlain(it.topic || 'general'),
      publishedTs: Number.isFinite(publishedTs) ? publishedTs : 0
    });
  }
}

const dedup = [];
const seen = new Set();
for (const item of all) {
  const key = `${item.url}|${normalize(item.title)}`;
  if (seen.has(key)) continue;
  seen.add(key);
  dedup.push(item);
}

const scoreItem = (item) => {
  let score = 0;
  if (item.publishedTs > 0) {
    const ageH = (now - item.publishedTs) / 3600000;
    score += Math.max(0, 48 - ageH);
  }
  if (germanRegex.test(`${item.title} ${item.summary}`)) score += 25;
  if (item.topic === 'regional') score += 20;
  if (item.topic === 'politics') score += 14;
  if (item.topic === 'tech') score += 10;
  if (item.summary.length > 120) score += 4;
  if (item.title.length < 20) score -= 6;
  return score;
};

const scored = dedup
  .map((item) => ({ ...item, score: scoreItem(item) }))
  .sort((a, b) => (b.score - a.score) || (b.publishedTs - a.publishedTs));

const headline = scored[0] || null;
const headlineKey = headline ? `${headline.url}|${normalize(headline.title)}` : '';

const byTopic = {
  regional: [],
  politics: [],
  tech: [],
  economy: [],
  traffic: [],
  warnings: [],
  energy: [],
  ai: []
};

for (const item of scored) {
  const key = `${item.url}|${normalize(item.title)}`;
  if (headlineKey && key === headlineKey) continue;
  if (byTopic[item.topic]) byTopic[item.topic].push(item);
}

const take = (arr, n) => arr.slice(0, Math.max(0, Number(n || 0)));
const selected = {
  headline,
  regional: take(byTopic.regional, maxByTopic.regional ?? 4),
  politics: take(byTopic.politics, maxByTopic.politics ?? 4),
  tech: take(byTopic.tech, maxByTopic.tech ?? 3),
  economy: take(byTopic.economy, maxByTopic.economy ?? 3),
  traffic: take(byTopic.traffic, maxByTopic.traffic ?? 2),
  warnings: take(byTopic.warnings, maxByTopic.warnings ?? 2),
  energy: take(byTopic.energy, maxByTopic.energy ?? 2),
  ai: take(byTopic.ai, maxByTopic.ai ?? 2)
};

const summarize = (text, maxChars) => {
  const cleaned = toPlain(text);
  if (!cleaned) return '';
  const parts = cleaned
    .split(/(?<=[.!?])\s+/)
    .map((s) => s.trim())
    .filter(Boolean);
  const picked = parts.slice(0, 4).join(' ');
  const limited = picked.slice(0, Math.max(120, maxChars || 380));
  return limited.length < picked.length ? `${limited.replace(/\s+[^\s]*$/, '')}...` : limited;
};

const esc = (s) => String(s || '')
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/"/g, '&quot;');

const lineToHtml = (item) => {
  const summary = summarize(item.summary, Number(cfg.summaryMaxChars || 380));
  return `<article class="news-item"><h3><a href="${esc(item.url)}" target="_blank" rel="noopener noreferrer">${esc(item.title)}</a></h3>${summary ? `<p>${esc(summary)}</p>` : ''}</article>`;
};

const sectionConfig = Array.isArray(cfg.sectionConfig) ? cfg.sectionConfig : [];
const sections = [];

if (selected.headline) {
  sections.push(`<section><h2>🏆 Headline of the day</h2>${lineToHtml(selected.headline)}</section>`);
}

for (const conf of sectionConfig) {
  const key = String(conf.key || '');
  const arr = Array.isArray(selected[key]) ? selected[key] : [];
  if (!arr.length) continue;
  sections.push(`<section><h2>${esc(String(conf.title || key))}</h2>${arr.map(lineToHtml).join('')}</section>`);
}

if (!sections.length) {
  sections.push('<section><h2>Daily News</h2><p>Heute keine relevanten News gefunden.</p></section>');
}

const generatedAt = new Date().toISOString();
const html = `<!doctype html>
<html lang="de">
<head>
  <meta charset="utf-8"/>
  <meta name="viewport" content="width=device-width, initial-scale=1"/>
  <title>Daily News</title>
  <style>
    :root {
      --bg: #f4f7fb;
      --card: #ffffff;
      --text: #17202a;
      --muted: #5f6c7a;
      --accent: #0f766e;
      --border: #dde5ee;
    }
    * { box-sizing: border-box; }
    body { margin: 0; font-family: ui-sans-serif, -apple-system, Segoe UI, Helvetica, Arial, sans-serif; color: var(--text); background: radial-gradient(circle at 10% -20%, #cfe9ff 0%, #f4f7fb 40%, #f4f7fb 100%); }
    main { max-width: 920px; margin: 0 auto; padding: 24px 16px 48px; }
    header { margin-bottom: 16px; }
    h1 { margin: 0 0 8px; font-size: 1.8rem; }
    .meta { color: var(--muted); font-size: 0.95rem; }
    section { background: var(--card); border: 1px solid var(--border); border-radius: 14px; padding: 16px; margin: 14px 0; box-shadow: 0 8px 18px rgba(10, 20, 40, 0.04); }
    h2 { margin: 0 0 12px; font-size: 1.1rem; }
    .news-item { padding: 10px 0; border-top: 1px dashed var(--border); }
    .news-item:first-of-type { border-top: 0; padding-top: 0; }
    .news-item h3 { margin: 0 0 8px; font-size: 1rem; line-height: 1.35; }
    .news-item p { margin: 0; color: var(--muted); line-height: 1.45; }
    a { color: var(--accent); text-decoration: none; }
    a:hover { text-decoration: underline; }
  </style>
</head>
<body>
  <main>
    <header>
      <h1>Daily News</h1>
      <div class="meta">Generiert: ${esc(generatedAt)} • Quellen mit Treffern: ${sourceResults.filter((s) => Array.isArray(s.items) && s.items.length > 0).length}/${sourceResults.length}</div>
    </header>
    ${sections.join('')}
  </main>
</body>
</html>`;

return [{
  json: {
    config: cfg,
    htmlB64: Buffer.from(html, 'utf8').toString('base64'),
    createdAt: new Date().toISOString()
  }
}];

const item = $input.first().json;
const cfg = item.config || {};
const ttlHours = Math.max(1, Number(cfg.ttlHours || 48));
const now = new Date();
const expires = new Date(now.getTime() + ttlHours * 3600 * 1000);
const rand = () => Math.random().toString(36).slice(2);
const pageId = `${Date.now().toString(36)}-${rand().slice(0, 6)}`;
const token = `${rand()}${rand()}${rand()}`.slice(0, 40);
const base = String(cfg.publicBaseUrl || '').replace(/\/+$/, '');
const path = String(cfg.websitePath || 'daily-news-show').replace(/^\/+/, '');
const publicUrl = `${base}/${path}/${pageId}?t=${token}`;

return [{
  json: {
    pageId,
    token,
    htmlB64: String(item.htmlB64 || ''),
    createdAt: now.toISOString(),
    expiresAt: expires.toISOString(),
    publicUrl,
    message: `[Daily News]\n${publicUrl}`,
    recipient: ''
  }
}];
